export default class WizardForm {
    constructor(containerId, config) {
        this.containerId = containerId;
        this.config = config;
        this.steps = config.steps;
        this.currentStep = 0;
        this.allowPrevious = config.allowPrevious !== undefined ? config.allowPrevious : true;
        this.finishButtonText = config.finishButtonText || 'Finish';
        this.finishButtonSubmit = config.finishButtonSubmit !== undefined ? config.finishButtonSubmit : false;
        this.formId = config.formId || '';

        this.container = typeof containerId === 'string' ? document.querySelector(containerId) : containerId;

        this._init();
    }

    destroy() {
        this.containerId = null;
        this.config = null;
        this.steps = null;
        this.currentStep = null;
        this.allowPrevious = null;
        this.finishButtonText = null;
        this.finishButtonSubmit = null;
        this.formId = null;
        this.container = null;
        this.progressBar = null;
        this.stepsIndicator = null;
        this.content = null;
        this.prevButton = null;
        this.nextButton  = null;
    }

    _init() {
        this.progressBar = this.container.querySelector('.progress-bar');
        this.stepsIndicator = this.container.querySelector('.progress-indicator');
        this.content = this.container.querySelector('.wizard-content');
        this.prevButton = this.container.closest('.modal-content').querySelector('.wizard-navigation > .prev-button');
        this.nextButton = this.container.closest('.modal-content').querySelector('.wizard-navigation > .next-button');

        this.renderStepsIndicator();
        this.updateContent();
        this.updateNavigation();
        this.updateProgress();
        
        if (this.formId) {
            const form = this.getElement('#' + this.formId);
            if (form) {
                form.addEventListener('reset', () => this.reset());
            }
        }

        for (const step of this.steps) {
            // Continue to the next step without initializing if skipWhen returns true
            if (typeof step.skipWhen === "function" && typeof step.skipWhen() === "boolean" && step.skipWhen()) {
                this.navigate(1);
                continue;
            }

            // If there is no skip callback, initialize current step and exit loop
            if (typeof step.onEnter === "function") {
                step.onEnter();
                break;
            }
        }

        this.prevButton.addEventListener('click', () => this.handleReturnPrevious());
        this.nextButton.addEventListener('click', () => this.handleNextOrFinish());
    }

    getElement(selector, context = document) {
        return context.querySelector(selector);
    }

    handleReturnPrevious() {
        if (this.config == null) {
            return;
        }
        if (typeof this.steps[this.currentStep - 1].onEnter === "function") {
            this.steps[this.currentStep - 1].onEnter();
        }
        this.navigate(-1);
    }

    renderStepsIndicator() {
        this.stepsIndicator.innerHTML = ''; // Clear existing steps indicator

        this.steps.forEach((step, index) => {
            const stepElement = document.createElement('li');
            const className = 'progress-step' +
                (index === this.currentStep ? ' active' : '') +
                (index < this.currentStep ? ' completed' : '');

            const content = `
                <span class="progress-step-icon">
                    <span class="vi-solid ${index < this.currentStep ? 'vi-check-circle' : 'vi-contrast'}"></span>
                </span>
                <span class="progress-step-title">${step.title}</span>
            `;

            stepElement.className = className;
            stepElement.innerHTML = content;
            this.stepsIndicator.appendChild(stepElement);
        });
    }

    updateContent() {
        this.content.querySelectorAll('.wizard-step').forEach((step, index) => {
            step.classList.toggle('active', index === this.currentStep);
        });
    }

    updateNavigation() {
        this.prevButton.disabled = !this.allowPrevious || this.currentStep === 0;
        this.nextButton.textContent = this.currentStep === this.steps.length - 1 ? this.finishButtonText : 'Next';

        // TODO: Commented out to not conflict with dynamic attribute change on the onEnter() callbacks

        //const isLastStep = this.currentStep === this.steps.length - 1;
        //if (isLastStep) {
        //    if (this.finishButtonSubmit) {
        //        this.nextButton.setAttribute('type', 'submit');
        //        if (this.formId) {
        //            this.nextButton.setAttribute('form', this.formId);
        //        }
        //    } else {
        //        this.nextButton.setAttribute('type', 'button');
        //        this.nextButton.removeAttribute('form');
        //    }
        //}
        //else {
        //    this.nextButton.setAttribute('type', 'button');
        //    this.nextButton.removeAttribute('form');
        //}
    }

    updateProgress() {
        const progress = ((this.currentStep + 1) / this.steps.length) * 100;
        this.progressBar.value = progress;
    }

    handleNextOrFinish() {
        // TODO: fix multi event listeners with initial null instance
        if (this.config == null) {
            return;
        }
        if (this.currentStep === this.steps.length - 1) {
            if (typeof this.steps[this.currentStep].onFinish === 'function') {
                this.steps[this.currentStep].onFinish();
            }
            if (!this.finishButtonSubmit) {
                // Handle non-submit finish action
            }
        } else {
            if (typeof this.steps[this.currentStep].onNext === "function") {
                this.steps[this.currentStep].onNext(() => this.navigate(1))
            }
        }
    }

    navigate(direction) {
        const newStep = this.currentStep + direction;
        if (newStep >= 0 && newStep < this.steps.length) {

            this.currentStep = newStep;
            if (typeof this.steps[this.currentStep].onEnter === 'function') {
                this.steps[this.currentStep].onEnter();
            }

            this.renderStepsIndicator();
            this.updateContent();
            this.updateNavigation();
            this.updateProgress();
        }
    }

    reset() {
        this.currentStep = 0;
        this.renderStepsIndicator();
        this.updateContent();
        this.updateNavigation();
        this.updateProgress();

        const form = this.getElement('#' + this.formId);
        if (form) {
            form.reset();
        }

        if (typeof this.steps[0].onEnter === 'function') {
            this.steps[0].onEnter();
        }
    }

    setAllowPrevious(allow) {
        this.allowPrevious = allow;
        this.updateNavigation();
    }

    setFinishButtonText(text) {
        this.finishButtonText = text;
        this.updateNavigation();
    }

    setFinishButtonSubmit(isSubmit) {
        this.finishButtonSubmit = isSubmit;
        this.updateNavigation();
    }

    setFormId(formId) {
        this.formId = formId;
        this.updateNavigation();
    }
}